#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int matrix[N * M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%d", &matrix[i * M + j]);
            }
        }
        qsort(matrix, N * M, sizeof(int), compare);
        int sum1 = 0, sum2 = 0;
        for (int i = N * M - 1; i >= 0; i--) {
            if (i % 2 == 0) {
                sum1 += matrix[i];
            } else {
                sum2 += matrix[i];
            }
        }
        if (sum1 > sum2) {
            printf("Cyborg\n");
        } else if (sum1 < sum2) {
            printf("Geno\n");
        } else {
            printf("Draw\n");
        }
    }
    return 0;
}

