let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextIntArray() {
    return nextLine().split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let [N, M] = nextIntArray();
    let matrix = [];
    for (let i = 0; i < N; i++) {
        let row = nextIntArray();
        matrix = matrix.concat(row);
